mapper.select:
SELECT lot_num, lot_code, item_name, code, current_qty, lot_date, type, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT l.lot_num, l.lot_code, i.name AS item_name, i.code, l.current_qty, l.lot_date,
i.type, COUNT(*) OVER() AS total_count FROM lot l LEFT JOIN item i ON l.item_num = i.item_num
AND l.lot_date >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND l.lot_date <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND i.type = #{item_type}
AND l.item_num = #{item_num}
AND (l.lot_code LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY l.lot_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE lot
SET current_qty = current_qty - #{deduct_qty}
WHERE lot_num = #{lot_num}
  AND current_qty >= #{deduct_qty}

mapper.select:
SELECT depth, lot_code, item_name, item_type, gubun, id_col, content_col, date_col, status_col, worker FROM ( /* ── 루트 롯 — 생산공정 ── */ SELECT 0 AS depth, l.lot_code, i.name AS item_name, i.type AS item_type, '생산공정' AS gubun, wo.order_id AS id_col, p.process_content AS content_col, TO_CHAR(wo.order_start, 'YYYY-MM-DD') AS date_col, wo.order_status AS status_col, e.ename AS worker FROM lot l JOIN item i ON l.item_num = i.item_num LEFT JOIN work_order wo ON l.order_num = wo.order_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN process p ON pp.item_num = p.item_num LEFT JOIN emp e ON wo.emp_num = e.emp_num WHERE l.lot_num = #{lot_num}
UNION ALL
/* ── 루트 롯 — 출하이력 ── */ SELECT 0 AS depth, l.lot_code, i.name AS item_name, i.type AS item_type, '출하' AS gubun, s.shipment_id AS id_col, v.vender_name AS content_col, TO_CHAR(s.shipment_date, 'YYYY-MM-DD') AS date_col, s.shipment_status AS status_col, e.ename AS worker FROM lot l JOIN item i ON l.item_num = i.item_num JOIN shipment_lot sl ON sl.lot_num = l.lot_num JOIN shipment s ON sl.shipment_num = s.shipment_num JOIN shipment_request sr ON s.shipment_request_num = sr.shipment_request_num JOIN vender v ON sr.vender_num = v.vender_num LEFT JOIN emp e ON s.emp_num = e.emp_num WHERE l.lot_num = #{lot_num}
UNION ALL
/* ── 자식 롯 (재귀) — 생산공정 ── */ SELECT LEVEL AS depth, lc.lot_code, ic.name AS item_name, ic.type AS item_type, '생산공정' AS gubun, woc.order_id AS id_col, pc.process_content AS content_col, TO_CHAR(woc.order_start, 'YYYY-MM-DD') AS date_col, woc.order_status AS status_col, ec.ename AS worker FROM lot_relation lr JOIN lot lc ON lr.lot_child = lc.lot_num JOIN item ic ON lc.item_num = ic.item_num LEFT JOIN work_order woc ON lc.order_num = woc.order_num LEFT JOIN production_plan ppc ON woc.plan_num = ppc.plan_num LEFT JOIN process pc ON ppc.item_num = pc.item_num LEFT JOIN emp ec ON woc.emp_num = ec.emp_num START WITH lr.lot_parent = #{lot_num} CONNECT BY PRIOR lr.lot_child = lr.lot_parent
UNION ALL
/* ── 자식 롯 (재귀) — 출하이력 ── */ SELECT LEVEL AS depth, lc.lot_code, ic.name AS item_name, ic.type AS item_type, '출하' AS gubun, sc.shipment_id AS id_col, vc.vender_name AS content_col, TO_CHAR(sc.shipment_date, 'YYYY-MM-DD') AS date_col, sc.shipment_status AS status_col, ec.ename AS worker FROM lot_relation lr JOIN lot lc ON lr.lot_child = lc.lot_num JOIN item ic ON lc.item_num = ic.item_num JOIN shipment_lot slc ON slc.lot_num = lc.lot_num JOIN shipment sc ON slc.shipment_num = sc.shipment_num JOIN shipment_request src ON sc.shipment_request_num = src.shipment_request_num JOIN vender vc ON src.vender_num = vc.vender_num LEFT JOIN emp ec ON sc.emp_num = ec.emp_num START WITH lr.lot_parent = #{lot_num} CONNECT BY PRIOR lr.lot_child = lr.lot_parent ) ORDER BY depth, gubun DESC
